import{_ as e,o as a,c as d,ag as o}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Math Namespace","description":"","frontmatter":{},"headers":[],"relativePath":"guide/math.md","filePath":"guide/math.md"}'),n={name:"guide/math.md"};function c(r,t,s,i,l,h){return a(),d("div",null,[...t[0]||(t[0]=[o(`<h1 id="math-namespace" tabindex="-1">Math Namespace <a class="header-anchor" href="#math-namespace" aria-label="Permalink to &quot;Math Namespace&quot;">​</a></h1><p>The <code>Math</code> namespace provides hardware-accelerated mathematical functions. All functions map directly to LLVM intrinsics or optimized C library calls — no overhead, single-instruction where possible.</p><blockquote><p><strong>No import needed.</strong> <code>Math.*</code> is a builtin namespace available everywhere.</p></blockquote><h2 id="quick-examples" tabindex="-1">Quick Examples <a class="header-anchor" href="#quick-examples" aria-label="Permalink to &quot;Quick Examples&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let angle = Math.PI / 4.0;</span></span>
<span class="line"><span>let s = Math.sin(angle);           // 0.7071...</span></span>
<span class="line"><span>let c = Math.cos(angle);           // 0.7071...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let x = Math.sqrt(144.0);          // 12.0</span></span>
<span class="line"><span>let p = Math.pow(2.0, 10.0);       // 1024.0</span></span>
<span class="line"><span>let bits = Math.popcount(0xFF);     // 8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let r = Math.random();             // [0.0, 1.0) random float</span></span>
<span class="line"><span>let clamped = Math.clamp(x, 0.0, 1.0);</span></span></code></pre></div><h2 id="trigonometric" tabindex="-1">Trigonometric <a class="header-anchor" href="#trigonometric" aria-label="Permalink to &quot;Trigonometric&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.sin(x)</code></td><td><code>f64 → f64</code></td><td>Sine (radians)</td></tr><tr><td><code>Math.cos(x)</code></td><td><code>f64 → f64</code></td><td>Cosine (radians)</td></tr><tr><td><code>Math.tan(x)</code></td><td><code>f64 → f64</code></td><td>Tangent (radians)</td></tr><tr><td><code>Math.asin(x)</code></td><td><code>f64 → f64</code></td><td>Arc sine → radians</td></tr><tr><td><code>Math.acos(x)</code></td><td><code>f64 → f64</code></td><td>Arc cosine → radians</td></tr><tr><td><code>Math.atan(x)</code></td><td><code>f64 → f64</code></td><td>Arc tangent → radians</td></tr><tr><td><code>Math.atan2(y, x)</code></td><td><code>(f64, f64) → f64</code></td><td>Two-arg arc tangent</td></tr></tbody></table><h2 id="hyperbolic" tabindex="-1">Hyperbolic <a class="header-anchor" href="#hyperbolic" aria-label="Permalink to &quot;Hyperbolic&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.sinh(x)</code></td><td><code>f64 → f64</code></td><td>Hyperbolic sine</td></tr><tr><td><code>Math.cosh(x)</code></td><td><code>f64 → f64</code></td><td>Hyperbolic cosine</td></tr><tr><td><code>Math.tanh(x)</code></td><td><code>f64 → f64</code></td><td>Hyperbolic tangent</td></tr><tr><td><code>Math.asinh(x)</code></td><td><code>f64 → f64</code></td><td>Inverse hyperbolic sine</td></tr><tr><td><code>Math.acosh(x)</code></td><td><code>f64 → f64</code></td><td>Inverse hyperbolic cosine</td></tr><tr><td><code>Math.atanh(x)</code></td><td><code>f64 → f64</code></td><td>Inverse hyperbolic tangent</td></tr></tbody></table><h2 id="exponential-logarithmic" tabindex="-1">Exponential &amp; Logarithmic <a class="header-anchor" href="#exponential-logarithmic" aria-label="Permalink to &quot;Exponential &amp; Logarithmic&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.exp(x)</code></td><td><code>f64 → f64</code></td><td>e^x</td></tr><tr><td><code>Math.exp2(x)</code></td><td><code>f64 → f64</code></td><td>2^x</td></tr><tr><td><code>Math.expm1(x)</code></td><td><code>f64 → f64</code></td><td>e^x - 1 (precise near 0)</td></tr><tr><td><code>Math.log(x)</code></td><td><code>f64 → f64</code></td><td>Natural log (ln)</td></tr><tr><td><code>Math.ln(x)</code></td><td><code>f64 → f64</code></td><td>Natural log (alias)</td></tr><tr><td><code>Math.log2(x)</code></td><td><code>f64 → f64</code></td><td>Base-2 logarithm</td></tr><tr><td><code>Math.log10(x)</code></td><td><code>f64 → f64</code></td><td>Base-10 logarithm</td></tr><tr><td><code>Math.log1p(x)</code></td><td><code>f64 → f64</code></td><td>ln(1+x) (precise near 0)</td></tr></tbody></table><h2 id="power-root" tabindex="-1">Power &amp; Root <a class="header-anchor" href="#power-root" aria-label="Permalink to &quot;Power &amp; Root&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.pow(base, exp)</code></td><td><code>(f64, f64) → f64</code></td><td>base^exp</td></tr><tr><td><code>Math.sqrt(x)</code></td><td><code>f64 → f64</code></td><td>Square root</td></tr><tr><td><code>Math.cbrt(x)</code></td><td><code>f64 → f64</code></td><td>Cube root</td></tr><tr><td><code>Math.rsqrt(x)</code></td><td><code>f64 → f64</code></td><td>1/√x (reciprocal sqrt)</td></tr></tbody></table><h2 id="rounding" tabindex="-1">Rounding <a class="header-anchor" href="#rounding" aria-label="Permalink to &quot;Rounding&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.floor(x)</code></td><td><code>f64 → f64</code></td><td>Round towards -∞</td></tr><tr><td><code>Math.ceil(x)</code></td><td><code>f64 → f64</code></td><td>Round towards +∞</td></tr><tr><td><code>Math.round(x)</code></td><td><code>f64 → f64</code></td><td>Round to nearest integer</td></tr><tr><td><code>Math.trunc(x)</code></td><td><code>f64 → f64</code></td><td>Truncate towards 0</td></tr><tr><td><code>Math.rint(x)</code></td><td><code>f64 → f64</code></td><td>Round to nearest (banker&#39;s rounding)</td></tr></tbody></table><h2 id="comparison-clamping" tabindex="-1">Comparison &amp; Clamping <a class="header-anchor" href="#comparison-clamping" aria-label="Permalink to &quot;Comparison &amp; Clamping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.min(a, b)</code></td><td><code>(numeric, numeric) → numeric</code></td><td>Minimum of two values</td></tr><tr><td><code>Math.max(a, b)</code></td><td><code>(numeric, numeric) → numeric</code></td><td>Maximum of two values</td></tr><tr><td><code>Math.clamp(x, lo, hi)</code></td><td><code>(numeric, numeric, numeric) → numeric</code></td><td>Clamp x to [lo, hi]</td></tr><tr><td><code>Math.abs(x)</code></td><td><code>numeric → numeric</code></td><td>Absolute value (int or float)</td></tr><tr><td><code>Math.sign(x)</code></td><td><code>f64 → f64</code></td><td>Returns -1, 0, or +1</td></tr></tbody></table><h2 id="activation-functions-ml" tabindex="-1">Activation Functions (ML) <a class="header-anchor" href="#activation-functions-ml" aria-label="Permalink to &quot;Activation Functions (ML)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.relu(x)</code></td><td><code>f64 → f64</code></td><td>max(0, x)</td></tr><tr><td><code>Math.sigmoid(x)</code></td><td><code>f64 → f64</code></td><td>1/(1+e^(-x))</td></tr><tr><td><code>Math.erf(x)</code></td><td><code>f64 → f64</code></td><td>Error function</td></tr></tbody></table><h2 id="bit-operations" tabindex="-1">Bit Operations <a class="header-anchor" href="#bit-operations" aria-label="Permalink to &quot;Bit Operations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.popcount(x)</code></td><td><code>int → int</code></td><td>Count set bits</td></tr><tr><td><code>Math.clz(x)</code></td><td><code>int → int</code></td><td>Count leading zeros</td></tr><tr><td><code>Math.ctz(x)</code></td><td><code>int → int</code></td><td>Count trailing zeros</td></tr><tr><td><code>Math.nextPowerOf2(x)</code></td><td><code>int → int</code></td><td>Next power of 2</td></tr><tr><td><code>Math.bswap(x)</code></td><td><code>int → int</code></td><td>Byte-swap (endian reverse)</td></tr></tbody></table><h2 id="random-numbers" tabindex="-1">Random Numbers <a class="header-anchor" href="#random-numbers" aria-label="Permalink to &quot;Random Numbers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.random()</code></td><td><code>→ f64</code></td><td>Random float in [0.0, 1.0)</td></tr></tbody></table><p>Fast PRNG (xoshiro256++) — <strong>NOT cryptographically secure</strong>. For crypto-safe randomness, use <a href="/docs/guide/crypto"><code>Crypto.secureRand()</code></a>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main(): i32 {</span></span>
<span class="line"><span>    let r = Math.random();       // 0.0 ≤ r &lt; 1.0</span></span>
<span class="line"><span>    let dice = (r * 6.0) as i32 + 1;  // 1-6</span></span>
<span class="line"><span>    println(&quot;Rolled: &quot;, dice);</span></span>
<span class="line"><span>    return 0;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="constants" tabindex="-1">Constants <a class="header-anchor" href="#constants" aria-label="Permalink to &quot;Constants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Constant</th><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>Math.PI</code></td><td>3.14159265...</td><td>π</td></tr><tr><td><code>Math.E</code></td><td>2.71828182...</td><td>Euler&#39;s number</td></tr><tr><td><code>Math.TAU</code></td><td>6.28318530...</td><td>τ = 2π</td></tr><tr><td><code>Math.INF</code></td><td>∞</td><td>Positive infinity</td></tr><tr><td><code>Math.NAN</code></td><td>NaN</td><td>Not-a-Number</td></tr></tbody></table><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let area = Math.PI * radius * radius;</span></span>
<span class="line"><span>let circumference = Math.TAU * radius;</span></span></code></pre></div><h2 id="type-promotion" tabindex="-1">Type Promotion <a class="header-anchor" href="#type-promotion" aria-label="Permalink to &quot;Type Promotion&quot;">​</a></h2><p>All functions accept both <code>f32</code> and <code>f64</code>. Integer arguments are automatically promoted to float:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = Math.sqrt(4);       // i32 → f64, returns 2.0</span></span>
<span class="line"><span>let y = Math.sin(0.5f32);   // f32 → f32 variant used</span></span>
<span class="line"><span>let z = Math.abs(-42);      // integer abs, stays i32</span></span></code></pre></div><h2 id="llvm-backend" tabindex="-1">LLVM Backend <a class="header-anchor" href="#llvm-backend" aria-label="Permalink to &quot;LLVM Backend&quot;">​</a></h2><p>Every <code>Math.*</code> function maps to a single LLVM intrinsic or optimized libm call:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Math.sin(x)   →  @llvm.sin.f64(x)        (1-2 cycles)</span></span>
<span class="line"><span>Math.sqrt(x)  →  @llvm.sqrt.f64(x)       (1 cycle, HW)</span></span>
<span class="line"><span>Math.abs(x)   →  @llvm.fabs.f64(x)       (1 cycle)</span></span>
<span class="line"><span>Math.pow(a,b) →  @llvm.pow.f64(a, b)     (libm call)</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/crypto">Crypto Namespace</a> — Hardware-accelerated cryptographic primitives</li><li><a href="/docs/guide/bit">Bit Namespace</a> — Parallel bit manipulation</li><li><a href="/docs/guide/simd">SIMD</a> — Auto-vectorization for arrays</li></ul>`,36)])])}const b=e(n,[["render",c]]);export{u as __pageData,b as default};
